        x = x + 1
        x = bar(x, flag)
        x = x + 1
        return x

    x = torch.randn(2, device="cuda")
    f_compiled = torch.compile(f, mode="reduce-overhead", fullgraph=True)
    _, code = run_and_get_code(f_compiled, x, True)
